This MicroProfile Health class checks available disk space. What will the /health endpoint return if freeSpace <= 100?

@Liveness
@ApplicationScoped
public class DiskSizeCheck implements HealthCheck {
  @Override
  public HealthCheckResponse call() {
    File file = new File("/");
    long freeSpace = file.getFreeSpace() / 1024 / 1024;
    return HealthCheckResponse.named("disk")
      .withData("remainingSpace", freeSpace)
      .status(freeSpace > 100)
      .build();
  }
}
